package com.hospital.management.controller.admin;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.DepartmentServiceImpl;import com.hospital.management.util.RequestUtil;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.Optional;
@WebServlet("/admin/departments/edit")public class DepartmentEditServlet extends HttpServlet{private final DepartmentService service;public DepartmentEditServlet(){this(new DepartmentServiceImpl());}public DepartmentEditServlet(DepartmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=Form.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Optional<Department>d=service.getDepartment(id);if(d.isEmpty()){r.sendError(404);return;}show(q,r,d.get());}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setCharacterEncoding("UTF-8");Long id=Form.id(q.getParameter("departmentId"));if(id==null){r.sendError(400);return;}Department d=Form.department(q,id);ServiceResult<Void>x=service.updateDepartment(d,RequestUtil.buildAuditContext(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/departments?message=updated");return;}if(x.getStatus()==ServiceResult.Status.NOT_FOUND){r.sendError(404);return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,d);}private void show(HttpServletRequest q,HttpServletResponse r,Department d)throws ServletException,IOException{q.setAttribute("formMode","EDIT");q.setAttribute("department",d);q.getRequestDispatcher("/WEB-INF/views/admin/departments/form.jsp").forward(q,r);}}
